import{_ as a,o as e,c as i,a2 as l}from"./chunks/framework.CGYl2SZ_.js";const t=JSON.parse('{"title":"architecture","description":"architecture 页面","frontmatter":{"title":"architecture","description":"architecture 页面"},"headers":[],"relativePath":"concepts/architecture.md","filePath":"concepts/architecture.md"}');const s=a({name:"concepts/architecture.md"},[["render",function(a,t,s,o,n,c){return e(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="网关架构" tabindex="-1">网关架构 <a class="header-anchor" href="#网关架构" aria-label="Permalink to &quot;网关架构&quot;">​</a></h1><h1 id="网关架构-1" tabindex="-1">网关架构 <a class="header-anchor" href="#网关架构-1" aria-label="Permalink to &quot;网关架构&quot;">​</a></h1><p>最后更新：2026-01-22</p><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><ul><li>一个单一的长期运行的<strong>网关</strong>拥有所有消息渠道（WhatsApp 通过 Baileys、Telegram 通过 grammY、Slack、Discord、Signal、iMessage、WebChat）。</li><li>控制平面客户端（macOS 应用、CLI、网页 UI、自动化）通过 <strong>WebSocket</strong> 连接到网关，连接到配置的绑定主机（默认 <code>127.0.0.1:18789</code>）。</li><li><strong>节点</strong>（macOS/iOS/Android/无头）也通过 <strong>WebSocket</strong> 连接，但声明 <code>role: node</code> 并带有明确的 caps/命令。</li><li>每个主机一个网关；它是唯一打开 WhatsApp 会话的地方。</li><li><strong>canvas 主机</strong>由网关 HTTP 服务器提供服务： <ul><li><code>/__openclaw__/canvas/</code>（代理可编辑的 HTML/CSS/JS）</li><li><code>/__openclaw__/a2ui/</code>（A2UI 主机） 它使用与网关相同的端口（默认 <code>18789</code>）。</li></ul></li></ul><h2 id="组件和流程" tabindex="-1">组件和流程 <a class="header-anchor" href="#组件和流程" aria-label="Permalink to &quot;组件和流程&quot;">​</a></h2><h3 id="网关-守护进程" tabindex="-1">网关（守护进程） <a class="header-anchor" href="#网关-守护进程" aria-label="Permalink to &quot;网关（守护进程）&quot;">​</a></h3><ul><li>维护提供商连接。</li><li>公开类型化 WS API（请求、响应、服务器推送事件）。</li><li>验证入站帧是否符合 JSON Schema。</li><li>发出如 <code>agent</code>、<code>chat</code>、<code>presence</code>、<code>health</code>、<code>heartbeat</code>、<code>cron</code> 等事件。</li></ul><h3 id="客户端-mac-应用-cli-网页管理" tabindex="-1">客户端（mac 应用 / CLI / 网页管理） <a class="header-anchor" href="#客户端-mac-应用-cli-网页管理" aria-label="Permalink to &quot;客户端（mac 应用 / CLI / 网页管理）&quot;">​</a></h3><ul><li>每个客户端一个 WS 连接。</li><li>发送请求（<code>health</code>、<code>status</code>、<code>send</code>、<code>agent</code>、<code>system-presence</code>）。</li><li>订阅事件（<code>tick</code>、<code>agent</code>、<code>presence</code>、<code>shutdown</code>）。</li></ul><h3 id="节点-macos-ios-android-无头" tabindex="-1">节点（macOS / iOS / Android / 无头） <a class="header-anchor" href="#节点-macos-ios-android-无头" aria-label="Permalink to &quot;节点（macOS / iOS / Android / 无头）&quot;">​</a></h3><ul><li>使用 <code>role: node</code> 连接到<strong>相同的 WS 服务器</strong>。</li><li>在 <code>connect</code> 中提供设备身份；配对是<strong>基于设备的</strong>（角色 <code>node</code>），批准存在于设备配对存储中。</li><li>公开如 <code>canvas.*</code>、<code>camera.*</code>、<code>screen.record</code>、<code>location.get</code> 等命令。</li></ul><p>协议详情：</p><ul><li><a href="/gateway/protocol.html">网关协议</a></li></ul><h3 id="webchat" tabindex="-1">WebChat <a class="header-anchor" href="#webchat" aria-label="Permalink to &quot;WebChat&quot;">​</a></h3><ul><li>使用网关 WS API 进行聊天历史和发送的静态 UI。</li><li>在远程设置中，通过与其他客户端相同的 SSH/Tailscale 隧道连接。</li></ul><h2 id="连接生命周期-单个客户端" tabindex="-1">连接生命周期（单个客户端） <a class="header-anchor" href="#连接生命周期-单个客户端" aria-label="Permalink to &quot;连接生命周期（单个客户端）&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sequenceDiagram</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Client</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Gateway</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Client-&gt;&gt;Gateway: req:connect</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Gateway--&gt;&gt;Client: res (ok)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Note right of Gateway: or res error + close</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Note left of Client: payload=hello-ok&lt;br&gt;snapshot: presence + health</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Gateway--&gt;&gt;Client: event:presence</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Gateway--&gt;&gt;Client: event:tick</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Client-&gt;&gt;Gateway: req:agent</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Gateway--&gt;&gt;Client: res:agent&lt;br&gt;ack {runId, status:&quot;accepted&quot;}</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Gateway--&gt;&gt;Client: event:agent&lt;br&gt;(streaming)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Gateway--&gt;&gt;Client: res:agent&lt;br&gt;final {runId, status, summary}</span></span></code></pre></div><h2 id="有线协议-摘要" tabindex="-1">有线协议（摘要） <a class="header-anchor" href="#有线协议-摘要" aria-label="Permalink to &quot;有线协议（摘要）&quot;">​</a></h2><ul><li>传输：WebSocket，带 JSON 负载的文本帧。</li><li>第一帧<strong>必须</strong>是 <code>connect</code>。</li><li>握手后： <ul><li>请求：<code>{type:&quot;req&quot;, id, method, params}</code> → <code>{type:&quot;res&quot;, id, ok, payload|error}</code></li><li>事件：<code>{type:&quot;event&quot;, event, payload, seq?, stateVersion?}</code></li></ul></li><li>如果设置了 <code>OPENCLAW_GATEWAY_TOKEN</code>（或 <code>--token</code>），<code>connect.params.auth.token</code> 必须匹配，否则套接字关闭。</li><li>幂等性键对于有副作用的方法（<code>send</code>、<code>agent</code>）是必需的，以安全重试；服务器保持短期去重缓存。</li><li>节点必须在 <code>connect</code> 中包含 <code>role: &quot;node&quot;</code> 加上 caps/commands/permissions。</li></ul><h2 id="配对-本地信任" tabindex="-1">配对 + 本地信任 <a class="header-anchor" href="#配对-本地信任" aria-label="Permalink to &quot;配对 + 本地信任&quot;">​</a></h2><ul><li>所有 WS 客户端（操作员 + 节点）在 <code>connect</code> 上包含<strong>设备身份</strong>。</li><li>新设备 ID 需要配对批准；网关为后续连接颁发<strong>设备令牌</strong>。</li><li><strong>本地</strong>连接（回环或网关主机自己的 tailnet 地址）可以自动批准，以保持同主机用户体验流畅。</li><li>所有连接都必须对 <code>connect.challenge</code> nonce 进行签名。</li><li>签名负载 <code>v3</code> 还绑定 <code>platform</code> + <code>deviceFamily</code>；网关在重新连接时固定配对的元数据，并要求元数据更改时修复配对。</li><li><strong>非本地</strong>连接仍然需要明确批准。</li><li>网关认证（<code>gateway.auth.*</code>）仍然适用于<strong>所有</strong>连接，无论是本地还是远程。</li></ul><p>详情：<a href="/gateway/protocol.html">网关协议</a>、<a href="/channels/pairing.html">配对</a>、<a href="/gateway/security.html">安全</a>。</p><h2 id="协议类型和代码生成" tabindex="-1">协议类型和代码生成 <a class="header-anchor" href="#协议类型和代码生成" aria-label="Permalink to &quot;协议类型和代码生成&quot;">​</a></h2><ul><li>TypeBox 模式定义协议。</li><li>从这些模式生成 JSON Schema。</li><li>从 JSON Schema 生成 Swift 模型。</li></ul><h2 id="远程访问" tabindex="-1">远程访问 <a class="header-anchor" href="#远程访问" aria-label="Permalink to &quot;远程访问&quot;">​</a></h2><ul><li><p>首选：Tailscale 或 VPN。</p></li><li><p>替代方案：SSH 隧道</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 18789:127.0.0.1:18789</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@host</span></span></code></pre></div></li><li><p>相同的握手 + 认证令牌也适用于隧道。</p></li><li><p>在远程设置中可以为 WS 启用 TLS + 可选固定。</p></li></ul><h2 id="操作快照" tabindex="-1">操作快照 <a class="header-anchor" href="#操作快照" aria-label="Permalink to &quot;操作快照&quot;">​</a></h2><ul><li>启动：<code>openclaw gateway</code>（前台，日志输出到 stdout）。</li><li>健康：通过 WS 的 <code>health</code>（也包含在 <code>hello-ok</code> 中）。</li><li>监督：launchd/systemd 用于自动重启。</li></ul><h2 id="不变量" tabindex="-1">不变量 <a class="header-anchor" href="#不变量" aria-label="Permalink to &quot;不变量&quot;">​</a></h2><ul><li>每个主机正好有一个网关控制单个 Baileys 会话。</li><li>握手是强制性的；任何非 JSON 或非 connect 的第一帧都是硬关闭。</li><li>事件不重放；客户端必须在间隙时刷新。</li></ul>',31)])])}]]);export{t as __pageData,s as default};
